class Solution:
    def isPossibleToCutPath(self, grid):
        m, n = len(grid), len(grid[0])
        def connected(g):
            from collections import deque
            if g[0][0] == 0 or g[m - 1][n - 1] == 0:
                return False
            seen = [[False] * n for _ in range(m)]
            seen[0][0] = True
            q = deque([(0, 0)])
            while q:
                r, c = q.popleft()
                for nr, nc in ((r + 1, c), (r, c + 1)):
                    if nr < m and nc < n and not seen[nr][nc] and g[nr][nc] == 1:
                        seen[nr][nc] = True
                        q.append((nr, nc))
            return seen[m - 1][n - 1]
        if not connected(grid):
            return True
        for i in range(m):
            for j in range(n):
                if (i, j) in ((0, 0), (m - 1, n - 1)):
                    continue
                flipped = [row[:] for row in grid]
                flipped[i][j] = 1 - flipped[i][j]
                if not connected(flipped):
                    return True
        return False

