class Solution:
    def isPossibleToCutPath(self, grid):
        m, n = len(grid), len(grid[0])
        reach1 = [[False] * n for _ in range(m)]
        reach1[0][0] = grid[0][0] == 1
        for i in range(m):
            for j in range(n):
                if i == 0 and j == 0:
                    continue
                if grid[i][j] == 0:
                    continue
                up = reach1[i - 1][j] if i > 0 else False
                left = reach1[i][j - 1] if j > 0 else False
                reach1[i][j] = up or left
        if not reach1[m - 1][n - 1]:
            return True
        reach2 = [[False] * n for _ in range(m)]
        reach2[m - 1][n - 1] = True
        for i in range(m - 1, -1, -1):
            for j in range(n - 1, -1, -1):
                if i == m - 1 and j == n - 1:
                    continue
                if grid[i][j] == 0:
                    continue
                down = reach2[i + 1][j] if i + 1 < m else False
                right = reach2[i][j + 1] if j + 1 < n else False
                reach2[i][j] = down or right
        for d in range(1, m + n - 2):
            cnt = 0
            lo = max(0, d - (n - 1))
            hi = min(m - 1, d)
            for i in range(lo, hi + 1):
                j = d - i
                if reach1[i][j] and reach2[i][j]:
                    cnt += 1
                    if cnt > 1:
                        break
            if cnt <= 1:
                return True
        return False

