var isPossibleToCutPath = function(grid) {
    const m = grid.length, n = grid[0].length;
    const reach1 = Array.from({length: m}, () => new Array(n).fill(false));
    reach1[0][0] = grid[0][0] === 1;
    for (let i = 0; i < m; i++) {
        for (let j = 0; j < n; j++) {
            if (i === 0 && j === 0) continue;
            if (grid[i][j] === 0) continue;
            const up = i > 0 ? reach1[i - 1][j] : false;
            const left = j > 0 ? reach1[i][j - 1] : false;
            reach1[i][j] = up || left;
        }
    }
    if (!reach1[m - 1][n - 1]) return true;
    const reach2 = Array.from({length: m}, () => new Array(n).fill(false));
    reach2[m - 1][n - 1] = true;
    for (let i = m - 1; i >= 0; i--) {
        for (let j = n - 1; j >= 0; j--) {
            if (i === m - 1 && j === n - 1) continue;
            if (grid[i][j] === 0) continue;
            const down = i + 1 < m ? reach2[i + 1][j] : false;
            const right = j + 1 < n ? reach2[i][j + 1] : false;
            reach2[i][j] = down || right;
        }
    }
    for (let d = 1; d <= m + n - 3; d++) {
        let cnt = 0;
        const lo = Math.max(0, d - (n - 1));
        const hi = Math.min(m - 1, d);
        for (let i = lo; i <= hi; i++) {
            const j = d - i;
            if (reach1[i][j] && reach2[i][j]) {
                cnt++;
                if (cnt > 1) break;
            }
        }
        if (cnt <= 1) return true;
    }
    return false;
};
